 1	import React, { FC } from 'react';
 2	
 3	import { V1InstancetypeMatcher, V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import CPUMemory from '@kubevirt-utils/components/CPUMemory/CPUMemory';
 5	import GuestAgentIsRequiredText from '@kubevirt-utils/components/GuestAgentIsRequiredText/GuestAgentIsRequiredText';
 6	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { getAnnotation } from '@kubevirt-utils/resources/shared';
 9	import {
10	  getDisks,
11	  getInterfaces,
12	  useVMIAndPodsForVM,
13	  VM_WORKLOAD_ANNOTATION,
14	} from '@kubevirt-utils/resources/vm';
15	import {
16	  getOperatingSystem,
17	  getOperatingSystemName,
18	} from '@kubevirt-utils/resources/vm/utils/operation-system/operationSystem';
19	import { useGuestOS } from '@kubevirt-utils/resources/vmi';
20	import { isEmpty } from '@kubevirt-utils/utils/utils';
21	import { FormGroup, TextListItem, TextListItemVariants } from '@patternfly/react-core';
22	
23	import InstanceTypeConfiguration from './InstanceTypeConfiguration';
24	
25	type ConfigurationSummaryProps = {
26	  vm: V1VirtualMachine;
27	};
28	
29	const ConfigurationSummary: FC<ConfigurationSummaryProps> = ({ vm }) => {
30	  const { t } = useKubevirtTranslation();
31	
32	  const itMatcher: V1InstancetypeMatcher = vm?.spec?.instancetype;
33	
34	  const { vmi } = useVMIAndPodsForVM(vm?.metadata?.name, vm?.metadata?.namespace);
35	  const [guestAgentData] = useGuestOS(vmi);
36	  const osName = (guestAgentData?.os?.prettyName || guestAgentData?.os?.name) ?? (
37	    <GuestAgentIsRequiredText vmi={vmi} />
38	  );
39	
40	  const interfaces = getInterfaces(vm);
41	
42	  return (
43	    <FormGroup fieldId="configuration" hasNoPaddingTop label={t('Configuration')}>
44	      <TextListItem className="text-muted" component={TextListItemVariants.dt}>
45	        {t('Operating system')}
46	      </TextListItem>
47	
48	      <TextListItem component={TextListItemVariants.dd}>
49	        {getOperatingSystemName(vm) || getOperatingSystem(vm) || osName}
50	      </TextListItem>
51	
52	      {itMatcher ? (
53	        <InstanceTypeConfiguration itMatcher={itMatcher} />
54	      ) : (
55	        <>
56	          <TextListItem className="text-muted" component={TextListItemVariants.dt}>
57	            {t('Flavor')}
58	          </TextListItem>
59	          <TextListItem component={TextListItemVariants.dd}>
60	            <CPUMemory vm={vm} vmi={vmi} />
61	          </TextListItem>
62	          <TextListItem className="text-muted" component={TextListItemVariants.dt}>
63	            {t('Workload profile')}
64	          </TextListItem>
65	          <TextListItem component={TextListItemVariants.dd}>
66	            {getAnnotation(vm?.spec?.template, VM_WORKLOAD_ANNOTATION) || (
67	              <MutedTextSpan text={t('Not available')} />
68	            )}
69	          </TextListItem>
70	        </>
71	      )}
72	      <TextListItem className="text-muted" component={TextListItemVariants.dt}>
73	        {t('NICs')}
74	      </TextListItem>
75	      <TextListItem component={TextListItemVariants.dd}>
76	        {(interfaces || [])?.map(({ model, name }) => (
77	          <div key={name}>{model ? `${name} - ${model}` : name}</div>
78	        ))}
79	        {isEmpty(interfaces) && <span className="text-muted">None</span>}
80	      </TextListItem>
81	      <TextListItem className="text-muted" component={TextListItemVariants.dt}>
82	        {t('Disks')}
83	      </TextListItem>
84	      <TextListItem component={TextListItemVariants.dd}>
85	        {(getDisks(vm) || [])?.map((disk) => (
86	          <div key={disk.name}>{disk.name}</div>
87	        ))}
88	      </TextListItem>
89	    </FormGroup>
90	  );
91	};
92	
93	export default ConfigurationSummary;

